// Validate + extract + generate report ID
const body = $input.first().json.body || $input.first().json;

const contact = body.contact || {};
const projectState = body.projectState || {};
const estimate = body.estimate || {};

// Validate required fields (phone is optional — gate submissions have name+email only)
if (!contact.name || !contact.email) {
  throw new Error('Missing required contact fields: name, email');
}
if (!body.calculator && !body.project_type) {
  if (projectState.deck_size || projectState.deck_height || projectState.material) {
    body.calculator = 'deck';
  } else {
    body.calculator = 'bathroom';
  }
}

// Generate 8-char report ID
const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let reportId = '';
for (let i = 0; i < 8; i++) reportId += chars[Math.floor(Math.random() * chars.length)];

// Parse name
const nameParts = contact.name.trim().split(/\s+/);
const firstName = nameParts[0] || '';
const lastName = nameParts.slice(1).join(' ') || '';

const calcType = (body.calculator || 'bathroom');
const calcLabel = calcType === 'deck' ? 'Deck' : 'Bathroom';

// Format selections for JT job description
const stateEntries = Object.entries(projectState)
  .filter(([k]) => k !== 'features')
  .map(([k, v]) => `${k.replace(/_/g, ' ')}: ${String(v).replace(/_/g, ' ')}`)
  .join('\n');

const features = (projectState.features || []).join(', ').replace(/_/g, ' ');

const jobDescription = [
  `Calculator: ${calcLabel}`,
  `Estimate: $${(estimate.low || 0).toLocaleString()} \u2013 $${(estimate.high || 0).toLocaleString()}`,
  '',
  stateEntries,
  features ? `Features: ${features}` : '',
  '',
  contact.preferred_date ? `Preferred call: ${contact.preferred_date}, ${contact.preferred_time || 'any time'}` : '',
  contact.notes ? `Notes: ${contact.notes}` : '',
  '',
  `Report: https://heartwoodcraft.me/report/?id=${reportId}`
].filter(Boolean).join('\n');

return [{
  json: {
    ...body,
    report_id: reportId,
    calculator: calcType,
    calc_label: calcLabel,
    contact_name: contact.name,
    contact_phone: contact.phone || null,
    contact_email: contact.email,
    contact_notes: contact.notes || '',
    first_name: firstName,
    last_name: lastName,
    project_state: projectState,
    estimate_low: estimate.low || 0,
    estimate_high: estimate.high || 0,
    preferred_date: contact.preferred_date || null,
    preferred_time: contact.preferred_time || null,
    attribution: body.attribution || null,
    landing_page: body.landing_page || '',
    referrer: body.referrer || '',
    source_page: body.source_page || '',
    job_description: jobDescription,
    report_url: `https://heartwoodcraft.me/report/?id=${reportId}`,
    jt_source_value: 'Website Calculator',
    jt_job_type: calcLabel,
    jt_job_name: `${contact.name}'s ${calcLabel} Project`.slice(0, 30)
  }
}];

const data = $input.first().json;

const lo = (data.estimate_low || 0).toLocaleString();
const hi = (data.estimate_high || 0).toLocaleString();
const calcLabel = data.calc_label || 'Project';
const firstName = data.first_name || data.contact_name || 'there';
const reportUrl = data.report_url;

const ps = data.project_state || {};
const features = (ps.features || []).join(', ').replace(/_/g, ' ');
const stateEntries = Object.entries(ps)
  .filter(([k]) => k !== 'features')
  .map(([k, v]) => `  ${k.replace(/_/g, ' ')}: ${String(v).replace(/_/g, ' ')}`)
  .join('\n');

const subject = `Your ${calcLabel} project summary from Heartwood Craft`;

const body = [
  `Hi ${firstName},`,
  ``,
  `Thanks for using the Heartwood Craft calculator. Here's a quick recap of your ${calcLabel.toLowerCase()} project:`,
  ``,
  `Estimated range: $${lo} – $${hi}`,
  ``,
  `Your selections:`,
  stateEntries,
  features ? `  features: ${features}` : '',
  ``,
  `View your full project summary here:`,
  reportUrl,
  ``,
  `What happens next:`,
  `  1. I'll give you a call to discuss your project and answer questions.`,
  `  2. We schedule a site visit (about 45 minutes at your home).`,
  `  3. I send you an itemized estimate, walked through together.`,
  `  4. If we're a fit, we set a start date.`,
  ``,
  `These ranges come from real Heartwood Craft jobs in the Gallatin Valley — not national averages. Your actual cost depends on site conditions, exact dimensions, and final material selections we'd nail down on the site visit.`,
  ``,
  `Talk soon,`,
  ``,
  `Eric O'Keefe`,
  `Heartwood Craft`,
  `406-551-5061`,
  `eric@iheartwoodcraft.com`,
  `https://heartwoodcraft.me`,
].filter(s => s !== false).join('\n');

return [{
  json: {
    ...data,
    email_to: data.contact_email,
    email_subject: subject,
    email_body: body,
  }
}];

