// Prep Calendar Event for khal
const data = $input.first().json;

const timeMap = {
  morning:   { start: '09:00', end: '09:15' },
  afternoon: { start: '13:00', end: '13:15' },
  evening:   { start: '17:00', end: '17:15' },
};

const tomorrow = new Date(Date.now() + 86400000).toISOString().split('T')[0];
const dateStr = data.preferred_date || tomorrow;
const times = timeMap[data.preferred_time] || timeMap.morning;

const name = (data.contact_name || '').replace(/"/g, '\\"');
const phone = (data.contact_phone || '').replace(/"/g, '\\"');
const calcType = data.calculator || 'bathroom';
const projectType = (data.project_state.project_type || '').replace(/"/g, '\\"');
const estLow = data.estimate_low;
const estHigh = data.estimate_high;

const noDate = !data.preferred_date;
const noTime = !data.preferred_time;

const descParts = [
  `Phone: ${phone}`,
  `Email: ${data.contact_email || 'n/a'}`,
  `Project: ${projectType}`,
  `Est: $${estLow}-$${estHigh}`,
  noDate ? 'NO DATE SET - defaulted to tomorrow' : '',
  noTime ? 'No time pref - defaulted to 9am' : '',
].filter(Boolean).join(', ');

const khal_command = [
  'khal new',
  `${dateStr} ${times.start}`,
  `${dateStr} ${times.end}`,
  `"Call ${name} - ${phone} (${calcType})"`,
  '::',
  `"${descParts}"`,
].join(' ');

return [{ json: { ...data, khal_command } }];

const grantKey = $env.JOBTREAD_GRANT_KEY;
if (!grantKey) throw new Error('Missing JOBTREAD_GRANT_KEY');

const prev = $input.first().json;

const query = {
  '$': { grantKey, notify: false },
  createAccount: {
    '$': {
      organizationId: '22Nm3uFevXMb',
      name: prev.contact_name,
      type: 'customer'
    },
    createdAccount: {
      id: {},
      name: {}
    }
  }
};

return [{ json: { ...prev, query } }];

const grantKey = $env.JOBTREAD_GRANT_KEY;
if (!grantKey) throw new Error('Missing JOBTREAD_GRANT_KEY');

const response = $input.first().json;
