if (prev.contact_email) customFieldValues[CUSTOM_FIELDS.email] = prev.contact_email;

const createContactArgs = {
  accountId: prev.jt_account_id,
  name:      prev.contact_name,
};
if (Object.keys(customFieldValues).length) {
  createContactArgs.customFieldValues = customFieldValues;
}

const query = {
  '$': { grantKey, notify: false },
  createContact: {
    '$': createContactArgs,
    createdContact: {
      id:   {},
      name: {}
    }
  }
};

return [{ json: { ...prev, jt_location_id: locationId || null, query } }];

const grantKey = $env.JOBTREAD_GRANT_KEY;
