const createJobArgs = {
  locationId:  prev.jt_location_id,
  name:        prev.jt_job_name,
  description: prev.job_description,
};

const query = {
  '$': { grantKey, notify: false },
  createJob: {
    '$': createJobArgs,
    createdJob: {
      id:     {},
      number: {},
      name:   {}
    }
  }
};

return [{ json: { ...prev, jt_contact_id: contactId || null, query } }];

const response = $input.first().json;
const prev = $('PAVE Create Job').first().json;

const jobId = response?.createJob?.createdJob?.id || null;
const jobNumber = response?.createJob?.createdJob?.number || null;

return [{ json: {
  ...prev,
  jt_job_id: jobId,
  jt_job_number: jobNumber,
  // jt_account_id and jt_contact_id are already on prev from upstream
}}];

