  prev.preferred_date ? `Preferred call: ${prev.preferred_date} ${prev.preferred_time || ''}`.trim() : '',
  ``,
  `Selections:`,
  Object.entries(prev.project_state || {})
    .filter(([k]) => k !== 'features')
    .map(([k, v]) => `  ${k.replace(/_/g, ' ')}: ${String(v).replace(/_/g, ' ')}`)
    .join('\n'),
  (prev.project_state?.features || []).length
    ? `  features: ${prev.project_state.features.join(', ').replace(/_/g, ' ')}`
    : '',
  ``,
  `Report: ${prev.report_url}`,
].filter(Boolean).join('\n');

const query = {
  '$': { grantKey, notify: false },
  createComment: {
    '$': {
      targetType: 'job',
      targetId:   prev.jt_job_id,
      name:       subject,
      message:    message,
      isVisibleToInternalRoles: true,
      isVisibleToCustomerRoles: false,
      isVisibleToVendorRoles:   false,
      isVisibleToAll:           false
    }
  }
};

return [{ json: { ...prev, query } }];
